const MovieCard: React.FC<{ movie: Movie; apiKeys: ApiKeys; showAwards?: boolean }> = ({ movie, apiKeys }) => {
  const [poster, setPoster] = useState<string | null>(null);
  const rating = movie["Your Rating"] ?? movie["IMDb Rating"];
  const colors = getRatingColors(rating);

  useEffect(() => {
    if (apiKeys.tmdb) {
      fetch(`https://api.themoviedb.org/3/search/movie?api_key=${apiKeys.tmdb}&query=${encodeURIComponent(movie.Title)}&year=${movie.Year}`)
        .then(res => res.json())
        .then(data => { if(data.results?.[0]?.poster_path) setPoster(`https://image.tmdb.org/t/p/w342${data.results[0].poster_path}`); });
    }
  }, [movie, apiKeys.tmdb]);

  return (
    <div className="group relative bg-[#050505] rounded-lg overflow-hidden transition-all duration-500 hover:scale-105 border border-white/5 hover:border-white/20">
      <div className="aspect-[2/3] w-full bg-slate-900 relative">
        {poster ? <img src={poster} alt={movie.Title} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-slate-800"><Film /></div>}
        <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent" />
      </div>
      <div className="p-4">
        <h3 className="font-bold text-white text-sm line-clamp-2">{movie.Title}</h3>
        <div className="flex items-center gap-2 mt-2">
            {movie["Your Rating"] && <div className={`flex items-center gap-1 text-xs font-black ${colors.text}`}><Star size={12} fill="currentColor"/> {movie["Your Rating"]}</div>}
            <div className="text-[10px] text-slate-500 font-bold">{movie.Year}</div>
        </div>
      </div>
    </div>
  );
};

