                      "{randomPick.Genres.split(',')[0]} dirigida por {randomPick.Directors.split(',')[0]}"
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        )}
      </main>

      {/* Settings Modal */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-[#0f172a] border border-slate-700 w-full max-w-lg rounded-3xl p-8 space-y-8">
