              <h2 className="text-2xl font-black uppercase flex items-center gap-3"><Settings className="text-accent"/> Configuración</h2>
              <button onClick={() => setIsSettingsOpen(false)}><X /></button>
            </div>
            <div className="space-y-4">
              <label className="block p-6 border border-dashed border-white/10 rounded-2xl bg-white/5 hover:bg-white/10 cursor-pointer">
                <div className="flex items-center gap-4">
                   <div className="p-3 bg-accent/20 rounded-xl text-accent"><FileText /></div>
                   <div><div className="font-black text-xs uppercase">Cargar Películas</div><div className="text-[10px] text-slate-500">CSV exportado de IMDb</div></div>
                </div>
                <input type="file" accept=".csv" className="hidden" onChange={async e => { if(e.target.files?.[0]) { setMovies(parseMoviesCSV(await e.target.files[0].text())); setIsSettingsOpen(false); } }} />
              </label>
              <button onClick={() => { setMovies([]); setOscarData([]); setIsSettingsOpen(false); }} className="w-full py-4 bg-red-500/10 text-red-500 border border-red-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-red-500/20 transition-all">Borrar Datos Locales</button>
            </div>
          </div>
        </div>
      )}

      <footer className="py-10 text-center border-t border-white/5 opacity-40 text-[10px] font-bold uppercase tracking-[0.5em]">Mi Cine © {new Date().getFullYear()}</footer>
    </div>
  );
}

