const AnalysisView: React.FC<{ movies: Movie[]; oscarData: OscarRow[] }> = ({ movies, oscarData }) => {
  const [subTab, setSubTab] = useState<'overview' | 'directors' | 'genres' | 'controversy'>('overview');
  const stats = useMemo(() => {
    if (movies.length === 0) return null;
    const rated = movies.filter(m => m["Your Rating"] !== null);
    const avg = rated.reduce((acc, m) => acc + (m["Your Rating"] || 0), 0) / rated.length || 0;
    const ratingDist = Array.from({ length: 10 }, (_, i) => ({ rating: i + 1, count: rated.filter(m => Math.round(m["Your Rating"] || 0) === i + 1).length }));
    const comparisons = movies.filter(m => m["Your Rating"] !== null && m["IMDb Rating"] !== null).map(m => ({ ...m, diff: (m["Your Rating"] || 0) - (m["IMDb Rating"] || 0) })).sort((a, b) => b.diff - a.diff);
    return { total: movies.length, avg, ratingDist, comparisons, underrated: comparisons.slice(0, 10), overrated: comparisons.slice().reverse().slice(0, 10) };
  }, [movies]);

  if (!stats) return <div className="p-20 text-center text-slate-600">No hay datos para analizar</div>;

  return (
    <div className="animate-in fade-in duration-700 space-y-12">
        <div className="flex gap-2">
            {['overview', 'directors', 'genres', 'controversy'].map(t => (
                <button key={t} onClick={() => setSubTab(t as any)} className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest ${subTab === t ? 'bg-accent text-black' : 'bg-white/5 text-slate-500'}`}>{t}</button>
            ))}
        </div>
        {subTab === 'overview' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="glass-panel p-8 rounded-3xl h-80"> 
                    <h4 className="text-xs font-black uppercase text-slate-500 mb-8">Distribución de Notas</h4> 
                    <ResponsiveContainer> 
                        <BarChart data={stats.ratingDist}> 
                            <XAxis dataKey="rating" stroke="#334155" fontSize={10}/> 
                            <Tooltip cursor={{fill: 'rgba(255,255,255,0.05)'}} contentStyle={{backgroundColor: '#0f172a', borderColor: '#334155'}}/> 
                            <Bar dataKey="count" fill="#eab308" radius={[4, 4, 0, 0]}/> 
                        </BarChart> 
                    </ResponsiveContainer> 
                </div>
                <div className="grid grid-cols-2 gap-4 h-80">
                    <div className="glass-panel p-8 rounded-3xl flex flex-col justify-center"> <span className="text-xs font-black text-slate-500 uppercase mb-2">Total Vistas</span> <span className="text-6xl font-black text-white">{stats.total}</span> </div>
                    <div className="glass-panel p-8 rounded-3xl flex flex-col justify-center"> <span className="text-xs font-black text-slate-500 uppercase mb-2">Nota Media</span> <span className="text-6xl font-black text-accent">{stats.avg.toFixed(2)}</span> </div>
                </div>
            </div>
        )}
        {subTab === 'controversy' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="glass-panel p-6 rounded-3xl"> 
                    <h4 className="text-xs font-black text-green-500 uppercase mb-6 flex items-center gap-2"> <ThumbsUp size={16}/> Joyas Infravaloradas </h4> 
                    <div className="space-y-3"> {stats.underrated.map(m => ( <div key={m.Title} className="flex justify-between items-center bg-black/20 p-4 rounded-xl"> <span className="text-xs font-bold text-white truncate pr-4">{m.Title}</span> <div className="flex gap-4 text-[10px] font-mono"> <span className="text-green-500">{m["Your Rating"]}</span> <span className="text-slate-600">vs</span> <span className="text-slate-500">{m["IMDb Rating"]}</span> </div> </div> ))} </div> 
                </div>
                <div className="glass-panel p-6 rounded-3xl"> 
                    <h4 className="text-xs font-black text-red-500 uppercase mb-6 flex items-center gap-2"> <ThumbsDown size={16}/> Decepciones </h4> 
