                <button onClick={() => setActivePopover(activePopover === 'genres' ? null : 'genres')} className={`px-5 py-2.5 rounded-xl border text-[10px] font-black uppercase tracking-[0.1em] flex items-center gap-2 ${filters.genres.length > 0 ? 'border-accent text-accent' : 'border-white/5 text-slate-400'}`}><Film size={14}/>Género {filters.genres.length > 0 && `(${filters.genres.length})`}</button>
