            </div>
            <button onClick={() => setFilters({ genres: [], directors: [], yearRange: [1900, 2025], ratingRange: [0, 10] })} className="px-5 py-2.5 text-red-500 hover:bg-red-500/10 rounded-xl transition-all border border-red-500/10"><Trash2 size={16}/></button>
        </div>
        {activePopover === 'year' && (
            <div className="flex gap-4 p-6 bg-slate-900 border border-white/10 rounded-2xl w-fit animate-in zoom-in-95">
