                        <button onClick={handleRandomPick}
                            className="shine-effect relative flex items-center gap-6 px-16 py-10 bg-black border border-accent/50 text-accent font-black text-3xl uppercase tracking-[0.2em] rounded-2xl hover:border-accent hover:shadow-[0_0_60px_rgba(234,179,8,0.3)] transition-all transform hover:scale-105 active:scale-95">
                            <Dice5 size={48} className="group-hover:rotate-180 transition-transform duration-700" />
                            <span>Qué ver hoy</span>
                        </button>
                    </div>
                    {randomPick ? (
                        <div className="max-w-sm w-full animate-in slide-in-from-bottom-8 duration-700">
                             <MovieCard movie={randomPick} apiKeys={DEFAULT_API_KEYS} />
                             <p className="mt-8 text-slate-500 text-sm italic font-serif tracking-wide">"El azar ha hablado, ¡disfruta la función!"</p>
                        </div>
                    ) : (
                        <div className="text-slate-500 uppercase tracking-[0.2em] text-xs max-w-xs mx-auto leading-relaxed">
                            {movies.length > 0 ? "Presiona el botón para elegir una película al azar de tu catálogo" : "Primero carga tu catálogo en configuración para recibir recomendaciones"}
                        </div>
                    )}
                </div>
            )}
      </main>

      {/* Settings Modal */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/95 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-[#0f172a] border border-slate-700 w-full max-w-lg rounded-3xl p-8 space-y-8 shadow-2xl">
            <div className="flex justify-between items-center"> <h2 className="text-2xl font-black uppercase flex items-center gap-3"><Settings className="text-accent"/> Configuración</h2> <button onClick={() => setIsSettingsOpen(false)} className="text-slate-500 hover:text-white"><X size={24} /></button> </div>
