      </main>

      <footer className="py-12 text-center border-t border-white/5 opacity-40 text-[10px] font-black uppercase tracking-[0.5em]">
          Mi Cine &copy; {new Date().getFullYear()} • v{APP_VERSION}
      </footer>
    </div>
  );
}

