// ==========================================
// 2. INTERFACES
// ==========================================

interface Movie {
  Title: string; Year: number | null; "Your Rating": number | null; "IMDb Rating": number | null;
  Genres: string; GenreList: string[]; Directors: string; URL: string; NormTitle: string;
}

interface OscarRow {
  FilmYear: number | null; AwardYear: number | null; Category: string; PersonName: string;
  Film: string; IsWinner: boolean; NormFilm: string;
}

interface ApiKeys { tmdb: string; omdb: string; youtube: string; }

// ==========================================
// 3. UTILIDADES
// ==========================================

const normalizeTitle = (s: any): string => {
  if (!s) return "";
  return String(s).replace(/[^a-z0-9]+/gi, "").toLowerCase();
};

const parseMoviesCSV = (csvText: string): Movie[] => {
  const result = Papa.parse(csvText, { header: true, skipEmptyLines: true });
  return (result.data as any[]).map(row => {
    let year = null;
    if (row.Year) {
      const match = String(row.Year).match(/(\d{4})/);
      if (match) year = parseInt(match[0], 10);
    }
    const yourRating = row["Your Rating"] ? parseFloat(row["Your Rating"]) : null;
    const imdbRating = row["IMDb Rating"] ? parseFloat(row["IMDb Rating"]) : null;
    return {
      Title: row.Title || "Untitled", Year: year, "Your Rating": yourRating, "IMDb Rating": imdbRating,
      Genres: row.Genres || "", GenreList: (row.Genres || "").split(", ").map((g: any) => g.trim()),
      Directors: row.Directors || "", URL: row.URL || "#", NormTitle: normalizeTitle(row.Title)
    };
  }).filter(m => m.Title !== "Untitled");
};

const parseOscarExcel = (buffer: ArrayBuffer): OscarRow[] => {
  const workbook = XLSX.read(buffer, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const jsonData = XLSX.utils.sheet_to_json(sheet) as any[];
  return jsonData.map(row => ({
    FilmYear: parseInt(String(row["Year Film"] || row["Year_Film"] || "0").match(/\d{4}/)?.[0] || "0"),
    AwardYear: parseInt(String(row["Year Award"] || row["Ceremony"] || "0").match(/\d{4}/)?.[0] || "0"),
    Category: String(row["Category"] || row["Award"] || "").trim().toUpperCase(),
    PersonName: String(row["Nominee"] || row["Name"] || ""),
    Film: String(row["Film"] || row["Movie"] || ""),
    IsWinner: /^(true|1|yes|won|winner)$/i.test(String(row["Winner"] || row["IsWinner"] || "")),
    NormFilm: normalizeTitle(row["Film"] || row["Movie"])
  }));
};

const getRatingColors = (rating: number | null) => {
  if (rating === null) return { text: "text-slate-500", border: "border-slate-800" };
  if (rating >= 9) return { text: "text-green-400", border: "border-green-500/30" };
  if (rating >= 7.5) return { text: "text-sky-400", border: "border-sky-500/30" };
  if (rating >= 6) return { text: "text-yellow-400", border: "border-yellow-500/30" };
  return { text: "text-orange-400", border: "border-orange-500/30" };
};

