  const rating = movie["Your Rating"] ?? movie["IMDb Rating"];
  const colors = getRatingColors(rating);

  return (
    <div className="group relative bg-[#050505] rounded-xl overflow-hidden transition-all duration-500 hover:scale-105 border border-white/5 hover:border-white/20 shadow-2xl">
      <div className="aspect-[2/3] relative overflow-hidden bg-slate-900">
