           <a href={movie.URL} target="_blank" className="p-2 bg-white/10 hover:bg-white/20 rounded text-white"><ExternalLink size={14} /></a>
           <a href={`https://www.youtube.com/results?search_query=${encodeURIComponent(movie.Title + " trailer")}`} target="_blank" className="p-2 bg-red-600/20 hover:bg-red-600/30 rounded text-red-400"><Youtube size={14} /></a>
        </div>
      </div>
    </div>
  );
};

const AFICard: React.FC<{ rank: number; title: string; year: number; movie: Movie | null; apiKeys: ApiKeys }> = ({ rank, title, year, movie, apiKeys }) => {
  const [tmdb, setTmdb] = useState<any>(null);
  useEffect(() => {
    if (apiKeys.tmdb) {
      fetch(`https://api.themoviedb.org/3/search/movie?api_key=${apiKeys.tmdb}&query=${encodeURIComponent(title)}&year=${year}`)
        .then(r => r.json()).then(d => d.results?.[0] && setTmdb(d.results[0]));
    }
  }, [title, year, apiKeys.tmdb]);

  return (
    <div className={`relative rounded-3xl border flex flex-col md:flex-row gap-8 p-8 transition-all duration-500 group ${movie ? 'bg-slate-900/60 border-yellow-500/30 shadow-2xl scale-[1.02]' : 'bg-black/40 border-white/5 grayscale opacity-60'}`}>
       <div className="flex flex-row md:flex-col gap-6 items-center shrink-0">
          <div className="text-6xl font-black italic text-white/10">#{rank}</div>
          <div className="w-24 h-36 bg-slate-800 rounded-xl overflow-hidden border border-white/10 shadow-xl">
             {tmdb?.poster_path ? <img src={`https://image.tmdb.org/t/p/w342${tmdb.poster_path}`} className="w-full h-full object-cover" /> : <Film className="m-auto mt-12 opacity-10" />}
          </div>
       </div>
       <div className="flex-1 flex flex-col justify-center">
          <h3 className="text-3xl font-black text-white group-hover:text-yellow-500 transition-colors">{title}</h3>
          <p className="text-sm text-slate-500 font-black uppercase tracking-widest mb-4">{year}</p>
          {movie && (
            <div className="flex items-center gap-4">
               <span className="px-3 py-1 bg-yellow-500 text-black text-[10px] font-black rounded-full">VISTO</span>
               <div className="flex items-center gap-1 text-yellow-500 font-black"><Star size={16} fill="currentColor"/> {movie["Your Rating"]}</div>
            </div>
          )}
       </div>
    </div>
  );
};

