    loadData();
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const availableGenres = useMemo(() => Array.from(new Set(movies.flatMap(m => m.GenreList))).sort(), [movies]);
  const availableDirectors = useMemo(() => Array.from(new Set(movies.flatMap(m => m.Directors.split(',').map(d => d.trim()).filter(Boolean)))).sort(), [movies]);

  useEffect(() => {
    let result = movies.filter(m => {
        const y = m.Year || 0;
        const r = m["Your Rating"] ?? -1;
        if (y !== 0 && (y < filters.yearRange[0] || y > filters.yearRange[1])) return false;
        if (filters.ratingRange[0] > 0 && (r < filters.ratingRange[0] || r > filters.ratingRange[1])) return false;
        if (filters.genres.length && !filters.genres.every(g => m.GenreList.includes(g))) return false;
        if (filters.directors.length && !filters.directors.some(d => m.Directors.includes(d))) return false;
        return true;
    });

    if (searchQuery.length > 1) {
       const fuse = new Fuse(result, { keys: ['Title', 'Directors', 'Genres', 'Year'], threshold: 0.3 });
       result = fuse.search(searchQuery).map(r => r.item);
    }
    setFilteredMovies(result);
    setCurrentPage(1);
  }, [movies, filters, searchQuery]);

  const totalPages = Math.ceil(filteredMovies.length / ITEMS_PER_PAGE);
  const paginatedMovies = useMemo(() => {
      const start = (currentPage - 1) * ITEMS_PER_PAGE;
      return filteredMovies.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredMovies, currentPage]);

  const [oscarYear, setOscarYear] = useState<number>(2024);

  const availableOscarYears = useMemo(() => {
    const years = new Set(oscarData.map(o => o.FilmYear).filter((y): y is number => y !== null));
    return Array.from(years).sort((a: number, b: number) => b - a);
  }, [oscarData]);

  const oscarFiltered = useMemo(() => {
    return oscarData.map(o => {
        const match = movies.find(m => m.NormTitle === o.NormFilm && m.Year === o.FilmYear);
        return { 
          ...o, 
          InMyCatalog: !!match, 
          MyRating: match?.["Your Rating"], 
          MyIMDb: match?.["IMDb Rating"], 
          CatalogURL: match?.URL 
        };
    });
  }, [oscarData, movies]);

  const oscarDisplayData = useMemo(() => {
    let data = oscarFiltered.filter(o => o.FilmYear === oscarYear);
    const grouped: Record<string, OscarRow[]> = {};
    data.forEach(item => {
        if (!grouped[item.Category]) grouped[item.Category] = [];
        grouped[item.Category].push(item);
    });
    return Object.entries(grouped).sort((a, b) => a[0].localeCompare(b[0]));
  }, [oscarFiltered, oscarYear]);

  const oscarLeaderboard = useMemo(() => {
      const yearData = oscarFiltered.filter(o => o.FilmYear === oscarYear);
      const statsMap: Record<string, {title: string, wins: number, noms: number, isWinner: boolean}> = {};
      yearData.forEach(row => {
          let entry = statsMap[row.Film];
          if (!entry) {
              entry = { title: row.Film, wins: 0, noms: 0, isWinner: false };
              statsMap[row.Film] = entry;
          }
          entry.noms += 1;
          if (row.IsWinner) {
              entry.wins += 1;
              entry.isWinner = true;
          }
      });
      return Object.values(statsMap).sort((a: any, b: any) => b.wins !== a.wins ? b.wins - a.wins : b.noms - a.noms);
  }, [oscarFiltered, oscarYear]);

  const handlePageChange = (newPage: number) => {
    setCurrentPage(newPage);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const GRID_CLASS = "grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 2xl:grid-cols-8 gap-x-6 gap-y-12";

  return (
    <div className="min-h-screen text-slate-200 font-sans flex flex-col relative">
      <div className="bg-cinematic"></div>
      <div className="bg-noise"></div>

      <SettingsModal 
        isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)}
        onFileUpload={(file, type) => {
            const reader = new FileReader();
            reader.onload = (e) => {
                if (type === 'movies') setMovies(parseMoviesCSV(e.target?.result as string));
                else setOscarData(parseOscarExcel(e.target?.result as ArrayBuffer));
            };
            if (type === 'movies') reader.readAsText(file); else reader.readAsArrayBuffer(file);
        }}
        onClearData={() => { setMovies([]); setOscarData([]); setFilteredMovies([]); }}
      />

      <header className={`sticky top-0 z-50 transition-all duration-500 border-b ${isScrolled ? 'bg-black/95 backdrop-blur-xl border-white/5 py-2' : 'bg-transparent border-transparent py-4'}`}>
          <div className="max-w-[1920px] mx-auto px-4 lg:px-8 h-16 flex items-center justify-between gap-6">
              <div className="flex items-center gap-3 shrink-0 group cursor-pointer" onClick={() => setActiveTab('catalog')}>
                  <div className="w-10 h-10 bg-gradient-to-br from-accent to-yellow-600 rounded-xl flex items-center justify-center text-primary shadow-[0_0_20px_rgba(234,179,8,0.4)]">
                      <Clapperboard size={24} strokeWidth={2.5} />
                  </div>
                  <div>
                      <h1 className="text-xl font-black uppercase tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent leading-none">Mi Cine</h1>
                      <div className="text-[10px] font-black text-accent tracking-[0.3em] uppercase opacity-90 mt-1">Catálogo Personal</div>
                  </div>
              </div>

              <div className="hidden md:flex flex-1 max-w-xl mx-auto px-4">
                  <div className="relative group w-full">
                       <input 
                           type="text" 
                           placeholder="Buscar película..." 
                           value={searchQuery}
                           onChange={(e) => setSearchQuery(e.target.value)}
                           className="w-full bg-white/5 border border-white/10 rounded-full py-2.5 pl-12 pr-4 text-sm focus:border-accent/50 outline-none backdrop-blur-md"
                       />
                       <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                  </div>
              </div>

              <nav className="flex items-center gap-4">
                  <div className="hidden lg:flex items-center gap-1">
                     {[
                        { id: 'catalog', label: 'Catálogo' },
                        { id: 'analysis', label: 'Análisis' },
                        { id: 'oscars', label: 'Premios Oscar' },
                        { id: 'afi', label: 'Lista AFI' },
                      ].map(tab => (
                        <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`px-4 py-2 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab.id ? 'text-white border-b-2 border-accent' : 'text-slate-500 hover:text-slate-300'}`}>
                            {tab.label}
                        </button>
                      ))}
                  </div>
                  <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-slate-400 hover:text-white transition-colors"><Settings size={20} /></button>
              </nav>
          </div>
      </header>

      <main className="max-w-[1920px] mx-auto p-4 lg:p-8 w-full flex-1 relative z-10">
            {activeTab === 'catalog' && (
                <div className="animate-in fade-in duration-700">
                    <FilterBar filters={filters} setFilters={setFilters} availableGenres={availableGenres} availableDirectors={availableDirectors} movies={movies} />
                    {isDataLoading && movies.length === 0 ? (
                        <div className="flex flex-col items-center justify-center py-40">
                            <Loader2 size={48} className="animate-spin text-accent mb-4" />
                            <p className="text-[10px] font-black uppercase tracking-widest text-slate-500">Iniciando Función...</p>
                        </div>
                    ) : filteredMovies.length === 0 ? (
                        <div className="text-center py-40 opacity-20"><Clapperboard size={80} className="mx-auto mb-4" /><p className="font-black uppercase tracking-widest">No se encontraron películas</p></div>
                    ) : (
                        <>
                            <div className={GRID_CLASS}>
                                {paginatedMovies.map((m, i) => <MovieCard key={`${m.Title}-${i}`} movie={m} apiKeys={apiKeys} />)}
                            </div>

                            {/* PAGINACIÓN RESTAURADA */}
                            {totalPages > 1 && (
                                <div className="mt-20 mb-12 flex flex-col items-center gap-4">
                                    <div className="flex items-center gap-6 glass-panel px-6 py-3 rounded-full border border-white/5 shadow-2xl">
                                        <button 
                                            disabled={currentPage === 1} 
                                            onClick={() => handlePageChange(currentPage - 1)}
                                            className="p-2 hover:bg-white/10 rounded-full disabled:opacity-20 transition-all text-accent"
                                        >
                                            <ChevronLeft size={24} />
                                        </button>
                                        <div className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">
                                            Página <span className="text-white text-lg font-black">{currentPage}</span> de <span className="text-white text-lg font-black">{totalPages}</span>
                                        </div>
                                        <button 
                                            disabled={currentPage >= totalPages} 
                                            onClick={() => handlePageChange(currentPage + 1)}
                                            className="p-2 hover:bg-white/10 rounded-full disabled:opacity-20 transition-all text-accent"
                                        >
                                            <ChevronRight size={24} />
                                        </button>
                                    </div>
                                    <div className="text-[9px] font-black uppercase tracking-[0.3em] text-slate-600">
                                        Explorando {filteredMovies.length} títulos
                                    </div>
                                </div>
                            )}
                        </>
                    )}
                </div>
            )}

            {activeTab === 'oscars' && (
                <div className="space-y-12 animate-in fade-in duration-700">
                    <div className="glass-panel p-8 rounded-3xl border border-white/5 relative overflow-hidden shadow-2xl">
                        <div className="flex flex-col md:flex-row items-center justify-between gap-8 mb-12">
                             <div className="flex items-center gap-6">
                                <div className="w-16 h-16 bg-yellow-500/10 rounded-full flex items-center justify-center border border-yellow-500/20 shadow-[0_0_30px_rgba(234,179,8,0.2)]">
                                    <Trophy size={32} className="text-yellow-500" />
                                </div>
                                <div><h2 className="text-4xl font-black uppercase text-yellow-500 tracking-tighter leading-none">Premios Oscar</h2><p className="text-[10px] text-yellow-500/60 font-black uppercase tracking-[0.2em] mt-2">Archivo Histórico</p></div>
                            </div>
                            <div className="flex items-center gap-4 bg-black/40 p-2 rounded-2xl border border-white/5 shadow-xl">
                                <button onClick={() => setOscarYear(oscarYear - 1)} className="p-3 hover:bg-white/5 rounded-xl transition-colors">Ant</button>
                                <div className="px-12 py-3 bg-yellow-500 text-black rounded-xl font-black text-3xl shadow-lg">{oscarYear}</div>
                                <button onClick={() => setOscarYear(oscarYear + 1)} className="p-3 hover:bg-white/5 rounded-xl transition-colors">Sig</button>
                            </div>
                        </div>
                        <div className="flex overflow-x-auto gap-2 pb-4 no-scrollbar scroll-smooth">
                            {availableOscarYears.map(y => (
                                <button key={y} onClick={() => setOscarYear(y)} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shrink-0 ${oscarYear === y ? 'bg-yellow-500 text-black shadow-xl' : 'bg-white/5 text-slate-500 hover:text-white hover:bg-white/10'}`}>{y}</button>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-20">
                        {oscarDisplayData.map(([cat, items]) => (
                            <div key={cat} className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                                <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.4em] mb-8 border-l-4 border-yellow-500 pl-4 bg-gradient-to-r from-yellow-500/5 to-transparent py-2">{cat}</h3>
                                <div className={GRID_CLASS}>
                                    {items.map((o, i) => (
                                        <OscarCard key={`${cat}-${i}`} item={o} apiKeys={apiKeys} />
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>

                    {oscarLeaderboard.length > 0 && (
                        <div className="mt-32 pt-16 border-t border-white/5">
                             <h3 className="text-2xl font-black text-white uppercase tracking-tight mb-12 flex items-center gap-4"><List className="text-yellow-500" /> Ranking por Película</h3>
                             <div className="flex flex-col lg:flex-row gap-8 h-[650px]">
                                 <div className="lg:w-1/3 glass-panel rounded-2xl border border-white/5 overflow-y-auto custom-scrollbar p-3 space-y-2 bg-black/20">
                                     {oscarLeaderboard.map((m) => (
                                         <button key={m.title} onClick={() => setSelectedOscarMovieTitle(m.title)} className={`w-full flex items-center justify-between p-4 rounded-xl transition-all border ${selectedOscarMovieTitle === m.title ? 'bg-yellow-500/10 border-yellow-500/40 shadow-xl' : 'bg-transparent border-transparent hover:bg-white/5'}`}>
                                             <div className="flex items-center gap-4 truncate pr-2">
                                                 {m.isWinner && <Trophy size={14} className="text-yellow-500 shrink-0" />}
                                                 <span className={`text-[11px] font-black uppercase tracking-wide truncate ${selectedOscarMovieTitle === m.title ? 'text-white' : 'text-slate-400'}`}>{m.title}</span>
                                             </div>
                                             <div className="flex gap-4 shrink-0"><span className="text-[10px] font-black text-yellow-500">{m.wins}W</span><span className="text-[10px] font-black text-slate-600">{m.noms}N</span></div>
                                         </button>
                                     ))}
                                 </div>
                                 <div className="lg:w-2/3 h-full">
                                     {selectedOscarMovieTitle ? (
                                         <OscarMovieSummary title={selectedOscarMovieTitle} year={oscarYear} oscarData={oscarData} apiKeys={apiKeys} movies={movies} />
                                     ) : (
                                         <div className="h-full glass-panel rounded-2xl border border-white/5 flex flex-col items-center justify-center opacity-40 italic text-sm text-center p-12">
                                             <Play size={48} className="mb-6 opacity-20" />
                                             <p className="uppercase tracking-[0.2em] font-black text-xs">Selecciona una película para ver el desglose</p>
                                         </div>
                                     )}
                                 </div>
                             </div>
                        </div>
                    )}
                </div>
            )}

            {activeTab === 'afi' && (
                 <div className="animate-in fade-in duration-700 max-w-6xl mx-auto space-y-12">
                    <div className="text-center mb-20">
                        <h2 className="text-6xl font-black uppercase italic tracking-tighter mb-4 bg-gradient-to-b from-white to-slate-500 bg-clip-text text-transparent leading-none">Lista AFI</h2>
                        <p className="text-accent font-black uppercase tracking-[0.6em] text-[10px]">100 Years... 100 Movies</p>
                    </div>
                    <div className="grid grid-cols-1 gap-8">
                        {AFI_LIST.map(a => (
                            <AFICard 
                                key={a.Rank} 
                                rank={a.Rank} 
                                title={a.Title} 
                                year={a.Year} 
                                movie={movies.find(m => m.NormTitle === normalizeTitle(a.Title))} 
                                apiKeys={apiKeys} 
                            />
                        ))}
                    </div>
                 </div>
            )}

            {activeTab === 'analysis' && <AnalysisView movies={movies} oscarData={oscarData} />}
      </main>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
// Fix: Added Movie to imports from ../types
import { FilterState, Movie } from '../types';
import { ChevronDown, Calendar, Star, Film, Megaphone, X, Check, Filter, Trash2 } from 'lucide-react';

interface FilterBarProps {
  filters: FilterState;
  setFilters: React.Dispatch<React.SetStateAction<FilterState>>;
  availableGenres: string[];
  availableDirectors: string[];
  // Fix: Added movies property to match usage in App.tsx
  movies: Movie[];
}

const FilterBar: React.FC<FilterBarProps> = ({
  filters, setFilters, availableGenres, availableDirectors, movies
}) => {
  const [activePopover, setActivePopover] = useState<'year' | 'rating' | 'genres' | 'directors' | null>(null);

  const togglePopover = (type: 'year' | 'rating' | 'genres' | 'directors') => {
    setActivePopover(activePopover === type ? null : type);
  };

  const handleRangeChange = (type: 'year' | 'rating', index: 0 | 1, val: string) => {
    const num = parseInt(val, 10);
    if (isNaN(num)) return;
    setFilters(prev => {
        const newRange = type === 'year' ? [...prev.yearRange] : [...prev.ratingRange];
        newRange[index] = num;
        // Fix: Explicitly cast to match the [number, number] tuple type
        return { ...prev, [type === 'year' ? 'yearRange' : 'ratingRange']: newRange as [number, number] };
    });
  };

  const toggleSelection = (type: 'genres' | 'directors', val: string) => {
    setFilters(prev => {
      const list = prev[type];
      return {
        ...prev,
        [type]: list.includes(val) ? list.filter(i => i !== val) : [...list, val]
      };
    });
  };

  const removeTag = (type: 'genres' | 'directors' | 'year' | 'rating', val?: string) => {
      if (type === 'genres' || type === 'directors') {
          if (val) toggleSelection(type, val);
      } else if (type === 'year') {
          setFilters(prev => ({ ...prev, yearRange: [1900, new Date().getFullYear()] }));
      } else if (type === 'rating') {
          setFilters(prev => ({ ...prev, ratingRange: [0, 10] }));
      }
  };

  const clearFilters = () => {
      setFilters(prev => ({
          ...prev,
          genres: [],
          directors: [],
          yearRange: [1900, new Date().getFullYear()],
          ratingRange: [0, 10]
      }));
      setActivePopover(null);
  };

  // Check active states
  const isYearActive = filters.yearRange[0] > 1900 || filters.yearRange[1] < new Date().getFullYear();
  const isRatingActive = filters.ratingRange[0] > 0 || filters.ratingRange[1] < 10;
  const hasActiveFilters = filters.genres.length > 0 || filters.directors.length > 0 || isYearActive || isRatingActive;

  // Render a Filter Button with Popover Logic
  const FilterButton = ({ id, label, icon: Icon, active, count, isFiltered }: { id: string, label: string, icon: any, active: boolean, count?: number, isFiltered?: boolean }) => (
    <div className="relative">
      <button 
        onClick={() => togglePopover(id as any)}
        className={`
            group flex items-center gap-2 px-4 py-2.5 rounded-xl border text-xs font-bold uppercase tracking-wider transition-all duration-300
            ${active 
                ? 'bg-[#0f172a] border-accent text-accent shadow-[0_0_15px_rgba(234,179,8,0.2)]' 
                : isFiltered 
                    ? 'bg-accent/10 border-accent/40 text-accent hover:bg-accent/20'
                    : 'bg-white/5 border-white/5 text-slate-400 hover:bg-white/10 hover:text-slate-200 hover:border-white/20'
            }
        `}
      >
        <Icon size={14} className={isFiltered || active ? 'text-accent' : 'text-slate-500 group-hover:text-slate-300'} />
        {label}
        {count ? <span className="ml-1 bg-accent text-black px-1.5 rounded-full text-[9px] font-black">{count}</span> : null}
        <ChevronDown size={12} className={`transition-transform duration-300 opacity-50 ${active ? 'rotate-180' : ''}`} />
      </button>

      {/* Popover */}
      {active && (
        <div className="absolute top-full mt-2 left-0 z-50 min-w-[300px] bg-[#0f172a]/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-5 animate-in fade-in slide-in-from-top-2 duration-200 origin-top-left">
           <div className="mb-4 flex justify-between items-center border-b border-white/5 pb-2">
             <span className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <Icon size={12}/> {label}
             </span>
             <button onClick={() => setActivePopover(null)} className="p-1 hover:bg-white/10 rounded-full transition-colors"><X size={14} className="text-slate-500 hover:text-white" /></button>
           </div>

           {id === 'year' && (
              <div className="space-y-4">
                  <div className="flex items-center gap-3">
                      <div className="flex-1">
                          <label className="text-[10px] uppercase text-slate-500 font-bold mb-1 block">Desde</label>
                          <input type="number" value={filters.yearRange[0]} onChange={e => handleRangeChange('year', 0, e.target.value)} 
                              className="w-full bg-black/40 border border-white/10 rounded-lg p-2.5 text-center text-sm font-mono focus:border-accent outline-none text-white transition-colors" placeholder="1900" />
                      </div>
                      <div className="flex-1">
                          <label className="text-[10px] uppercase text-slate-500 font-bold mb-1 block">Hasta</label>
                          <input type="number" value={filters.yearRange[1]} onChange={e => handleRangeChange('year', 1, e.target.value)} 
                              className="w-full bg-black/40 border border-white/10 rounded-lg p-2.5 text-center text-sm font-mono focus:border-accent outline-none text-white transition-colors" placeholder="2024" />
                      </div>
                  </div>
                  <div className="text-[10px] text-slate-500 text-center">Rango de estrenos</div>
              </div>
           )}

           {id === 'rating' && (
              <div className="space-y-4">
                  <div className="flex items-center gap-3">
                      <div className="flex-1">
                          <label className="text-[10px] uppercase text-slate-500 font-bold mb-1 block">Mínima</label>
                          <input type="number" min="0" max="10" value={filters.ratingRange[0]} onChange={e => handleRangeChange('rating', 0, e.target.value)} 
                              className="w-full bg-black/40 border border-white/10 rounded-lg p-2.5 text-center text-sm font-mono focus:border-accent outline-none text-white transition-colors" />
                      </div>
                      <div className="flex-1">
                           <label className="text-[10px] uppercase text-slate-500 font-bold mb-1 block">Máxima</label>
                          <input type="number" min="0" max="10" value={filters.ratingRange[1]} onChange={e => handleRangeChange('rating', 1, e.target.value)} 
                              className="w-full bg-black/40 border border-white/10 rounded-lg p-2.5 text-center text-sm font-mono focus:border-accent outline-none text-white transition-colors" />
                      </div>
                  </div>
                  <div className="text-[10px] text-slate-500 text-center">Nota personal o IMDb</div>
              </div>
           )}

           {id === 'genres' && (
              <div className="flex flex-wrap gap-2 max-h-56 overflow-y-auto custom-scrollbar pr-1">
                  {availableGenres.map(g => (
                      <button key={g} onClick={() => toggleSelection('genres', g)}
                          className={`text-[11px] px-3 py-1.5 rounded-lg border transition-all duration-200 ${filters.genres.includes(g) ? 'bg-accent text-black border-accent font-bold shadow-lg shadow-accent/20' : 'bg-white/5 border-white/5 text-slate-400 hover:border-white/20 hover:text-white'}`}>
                          {g}
                      </button>
                  ))}
              </div>
           )}

            {id === 'directors' && (
              <div className="space-y-2">
                 <input type="text" placeholder="Filtrar lista..." className="w-full bg-black/40 border-b border-white/10 p-2 text-xs text-white mb-2 outline-none focus:border-accent/50" onClick={(e) => e.stopPropagation()} />
                 <div className="max-h-60 overflow-y-auto custom-scrollbar space-y-0.5">
                    {availableDirectors.map(d => (
                        <button key={d} onClick={() => toggleSelection('directors', d)}
                            className={`w-full text-left text-xs px-3 py-2 rounded-lg flex justify-between items-center transition-colors ${filters.directors.includes(d) ? 'bg-accent/10 text-accent font-bold' : 'text-slate-400 hover:bg-white/5 hover:text-white'}`}>
                            {d}
                            {filters.directors.includes(d) && <Check size={12} />}
                        </button>
                    ))}
                 </div>
              </div>
           )}
        </div>
      )}
    </div>
  );

  return (
    <div className="flex flex-col gap-4">
        {/* Main Toolbar */}
        <div className="flex flex-wrap items-center gap-3 p-1.5 bg-black/20 backdrop-blur-md rounded-2xl border border-white/5 w-fit">
