import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';
import Fuse from 'fuse.js';
import { 
  Search, Trophy, Clapperboard, List, Settings, Loader2, Play, 
  ChevronLeft, ChevronRight, Filter, Trash2, Calendar, Star, 
  Film, Megaphone, X, Check, Activity, TrendingUp, TrendingDown, 
  Users, PieChart, Clock, ThumbsUp, ThumbsDown, ExternalLink, 
  PlayCircle, Youtube, BookOpen, CheckCircle2, FileText, History, 
  AlertTriangle 
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, 
  AreaChart, Area, ScatterChart, Scatter, Cell, ReferenceLine
} from 'recharts';

// ====================== TYPES ======================
export interface Movie {
  Title: string;
  Year: number | null;
  "Your Rating": number | null;
  "IMDb Rating": number | null;
  Genres: string;
  GenreList: string[];
  Directors: string;
  "Date Rated": string | null;
  URL: string;
  NormTitle: string;
  SearchText: string;
}

export interface OscarRow {
  FilmYear: number | null;
  AwardYear: number | null;
  CategoryRaw: string;
  Category: string;
  PersonName: string;
  Film: string;
  IsWinner: boolean;
  NormFilm: string;
  InMyCatalog?: boolean;
  MyRating?: number | null;
  MyIMDb?: number | null;
  CatalogURL?: string;
}

export interface TmdbInfo {
  id: number;
  poster_url: string | null;
  vote_average: number;
}

export interface ProviderInfo {
  platforms: string[];
  link: string | null;
}

export interface OmdbAwards {
  raw: string | null;
  oscars: number;
  emmys: number;
  baftas: number;
  golden_globes: number;
  palme_dor: boolean;
  oscars_nominated: number;
  total_wins: number;
  total_nominations: number;
  imdbRating?: string;
  error?: string;
}

export interface FilterState {
  yearRange: [number, number];
  ratingRange: [number, number];
  genres: string[];
  directors: string[];
}

export interface ApiKeys {
  tmdb: string;
  omdb: string;
  youtube: string;
}

// ====================== CONSTANTS & UTILS ======================
const APP_VERSION = "1.3.1";

const DEFAULT_API_KEYS: ApiKeys = {
  tmdb: "506c9387e637ecb32fd3b1ab6ade4259",
  omdb: "1b00f496",
  youtube: "AIzaSyBV8-kbLUzPAT9Pi1JBXP9KQBAjF0gvRHo"
};

const ITEMS_PER_PAGE = 48;

const normalizeTitle = (s: any): string => {
  if (!s) return "";
  return String(s).replace(/[^a-z0-9]+/gi, "").toLowerCase();
};

const parseMoviesCSV = (csvText: string): Movie[] => {
  const result = Papa.parse(csvText, { header: true, skipEmptyLines: true });
  const data = result.data as any[];
  return data.map(row => {
    let year = null;
    if (row.Year) {
      const match = String(row.Year).match(/(\d{4})/);
      if (match) year = parseInt(match[0], 10);
    }
    const yourRating = row["Your Rating"] ? parseFloat(row["Your Rating"]) : null;
    const imdbRating = row["IMDb Rating"] ? parseFloat(row["IMDb Rating"]) : null;
    const genres = row.Genres || "";
    const genreList = genres ? genres.split(", ").map((g:string) => g.trim()) : [];
    const directors = row.Directors || "";
    const searchFields = [row.Title, row["Original Title"], directors, genres, year, yourRating, imdbRating];
    const searchText = searchFields.filter(Boolean).join(" ").toLowerCase();
    return {
      Title: row.Title,
      Year: year,
      "Your Rating": yourRating,
      "IMDb Rating": imdbRating,
      Genres: genres,
      GenreList: genreList,
      Directors: directors,
      "Date Rated": row["Date Rated"] || null,
      URL: row.URL || "",
      NormTitle: normalizeTitle(row.Title),
      SearchText: searchText
    };
  }).filter(m => m.Title);
};

const parseOscarExcel = (buffer: ArrayBuffer) => {
  const workbook = XLSX.read(buffer, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const jsonData = XLSX.utils.sheet_to_json(sheet) as any[];
  return jsonData.map(row => {
    const filmYear = row["Year Film"] || row["Year_Film"] || row["year film"] || row["Year"] || null;
    const awardYear = row["Year Award"] || row["Ceremony"] || filmYear;
    const isWinner = !!(String(row["Winner"] || row["IsWinner"] || row["Won"]).match(/^(true|1|yes|won|winner)$/i));
    return {
      FilmYear: typeof filmYear === 'number' ? filmYear : parseInt(String(filmYear).match(/\d{4}/)?.[0] || '0'),
      AwardYear: typeof awardYear === 'number' ? awardYear : parseInt(String(awardYear).match(/\d{4}/)?.[0] || '0'),
      Category: String(row["Category"] || row["Award"] || "").trim().toUpperCase(),
      PersonName: String(row["Nominee"] || row["Name"] || ""),
      Film: String(row["Film"] || row["Movie"] || row["Title"] || ""),
      IsWinner: isWinner,
      NormFilm: normalizeTitle(row["Film"] || row["Movie"] || row["Title"] || "")
    };
  });
};

const getRatingColors = (rating: number | null) => {
  if (rating === null) return { border: "rgba(148,163,184,0.8)", glow: "rgba(15,23,42,0.0)", text: "text-slate-400" };
  if (rating >= 9) return { border: "#22c55e", glow: "rgba(34,197,94,0.55)", text: "text-green-500" };
  if (rating >= 8) return { border: "#0ea5e9", glow: "rgba(14,165,233,0.55)", text: "text-sky-500" };
  if (rating >= 7) return { border: "#a855f7", glow: "rgba(168,85,247,0.50)", text: "text-purple-500" };
  if (rating >= 6) return { border: "#eab308", glow: "rgba(234,179,8,0.45)", text: "text-yellow-500" };
  return { border: "#f97316", glow: "rgba(249,115,22,0.45)", text: "text-orange-500" };
};

// ====================== API SERVICES ======================
const TMDB_BASE = "https://api.themoviedb.org/3";
const TMDB_IMG = "https://image.tmdb.org/t/p/w342";

const fetchTmdbInfo = async (title: string, year: number | null, apiKey: string): Promise<TmdbInfo | null> => {
  if (!apiKey || !title) return null;
  try {
    const query = new URLSearchParams({ api_key: apiKey, query: title });
    if (year) query.append("year", year.toString());
    const res = await fetch(`${TMDB_BASE}/search/movie?${query}`);
    const data = await res.json();
    if (data.results?.length > 0) {
      const m = data.results[0];
      return { id: m.id, poster_url: m.poster_path ? `${TMDB_IMG}${m.poster_path}` : null, vote_average: m.vote_average };
    }
  } catch (e) {}
  return null;
};

const fetchOmdbAwards = async (title: string, year: number | null, apiKey: string): Promise<OmdbAwards | null> => {
  if (!apiKey || !title) return null;
  try {
    const query = new URLSearchParams({ apikey: apiKey, t: title, type: 'movie' });
    if (year) query.append('y', year.toString());
    const res = await fetch(`https://www.omdbapi.com/?${query}`);
    const data = await res.json();
    if (data.Response === "True") {
        const lower = (data.Awards || "").toLowerCase();
        const getNum = (regex: RegExp) => { const m = lower.match(regex); return m ? parseInt(m[1], 10) : 0; };
        return {
            raw: data.Awards === "N/A" ? null : data.Awards,
            oscars: getNum(/won\s+(\d+)\s+oscars?/),
            oscars_nominated: getNum(/nominated\s+for\s+(\d+)\s+oscars?/),
            emmys: getNum(/won\s+(\d+)\s+emmy/),
            baftas: lower.includes("bafta") ? 1 : 0,
            golden_globes: lower.includes("golden globe") ? 1 : 0,
            palme_dor: lower.includes("palme d'or"),
            total_wins: getNum(/(\d+)\s+wins?/),
            total_nominations: getNum(/(\d+)\s+nominations?/),
            imdbRating: data.imdbRating !== "N/A" ? data.imdbRating : undefined
        };
    }
  } catch (e) {}
  return null;
};

const getYoutubeTrailer = async (title: string, year: number | null, apiKey: string): Promise<string | null> => {
    if (!apiKey || !title) return null;
    try {
        const q = `${title} trailer ${year || ''}`;
        const res = await fetch(`https://www.googleapis.com/youtube/v3/search?part=snippet&q=${encodeURIComponent(q)}&type=video&maxResults=1&key=${apiKey}`);
        const data = await res.json();
        return data.items?.[0]?.id?.videoId || null;
    } catch (e) {}
    return null;
};

// ====================== COMPONENTS ======================

const MovieCard: React.FC<{ movie: Movie; apiKeys: ApiKeys }> = ({ movie, apiKeys }) => {
  const [tmdb, setTmdb] = useState<TmdbInfo | null>(null);
  const [awards, setAwards] = useState<OmdbAwards | null>(null);
  const [trailerId, setTrailerId] = useState<string | null>(null);

  useEffect(() => {
    fetchTmdbInfo(movie.Title, movie.Year, apiKeys.tmdb).then(setTmdb);
    fetchOmdbAwards(movie.Title, movie.Year, apiKeys.omdb).then(setAwards);
    getYoutubeTrailer(movie.Title, movie.Year, apiKeys.youtube).then(setTrailerId);
  }, [movie, apiKeys]);

  const rating = movie["Your Rating"] ?? movie["IMDb Rating"];
  const colors = getRatingColors(rating);
  const trailerUrl = trailerId ? `https://www.youtube.com/watch?v=${trailerId}` : `https://www.youtube.com/results?search_query=${encodeURIComponent(movie.Title + " trailer")}`;

  return (
    <div className="group relative bg-[#050505] rounded-lg overflow-hidden transition-all duration-500 hover:scale-105 hover:shadow-2xl border border-white/5 hover:border-white/20">
      <div className="aspect-[2/3] w-full bg-slate-900 relative overflow-hidden">
        {tmdb?.poster_url ? <img src={tmdb.poster_url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt="" /> : <div className="w-full h-full flex items-center justify-center text-slate-800"><Film size={32} /></div>}
        <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-60 group-hover:opacity-90" />
        <div className="absolute top-2 left-2 flex gap-1">
            {awards?.oscars ? <span className="bg-yellow-500 text-black text-[9px] px-1.5 py-0.5 rounded font-black">🏆 {awards.oscars}</span> : null}
        </div>
      </div>
      <div className="absolute bottom-0 left-0 right-0 p-3 transform translate-y-2 group-hover:translate-y-0 transition-transform duration-300">
        <h3 className="font-bold text-white text-[13px] leading-tight mb-0.5 line-clamp-2">{movie.Title}</h3>
        <div className="text-[10px] text-slate-400 mb-2">{movie.Year}</div>
        <div className="flex items-center gap-2 text-[11px] mb-2">
            {movie["Your Rating"] && <div className={`flex items-center gap-0.5 font-black ${colors.text}`}><Star size={10} fill="currentColor" /> {movie["Your Rating"]}</div>}
            {movie["IMDb Rating"] && <div className="text-slate-500"><span className="text-[9px] text-yellow-500 border border-yellow-500/30 px-0.5 rounded mr-1">IMDb</span>{movie["IMDb Rating"]}</div>}
        </div>
        <div className="h-0 group-hover:h-auto overflow-hidden opacity-0 group-hover:opacity-100 transition-all border-t border-white/10 pt-2 flex gap-1">
             <a href={movie.URL} target="_blank" rel="noreferrer" className="flex-1 py-1 bg-white/10 hover:bg-white/20 rounded flex justify-center"><ExternalLink size={12} /></a>
             <a href={trailerUrl} target="_blank" rel="noreferrer" className="flex-1 py-1 bg-red-500/10 hover:bg-red-500/20 rounded flex justify-center text-red-500"><Youtube size={12} /></a>
        </div>
      </div>
    </div>
  );
};

const OscarCard: React.FC<{ item: OscarRow; apiKeys: ApiKeys }> = ({ item, apiKeys }) => {
  const [tmdb, setTmdb] = useState<TmdbInfo | null>(null);
  useEffect(() => { fetchTmdbInfo(item.Film, item.FilmYear, apiKeys.tmdb).then(setTmdb); }, [item, apiKeys]);
