        {tmdb?.poster_url ? <img src={tmdb.poster_url} className="w-full h-full object-cover" alt="" /> : <div className="w-full h-full flex items-center justify-center text-slate-800"><Film size={24} /></div>}
        {item.IsWinner && <div className="absolute top-2 left-2 bg-yellow-500 text-black text-[8px] font-black px-1.5 py-0.5 rounded">GANADOR</div>}
        {item.InMyCatalog && <div className="absolute top-2 right-2 bg-green-500 text-white text-[8px] font-black px-1.5 py-0.5 rounded">VISTO</div>}
      </div>
      <div className="p-3">
        <h4 className="font-black text-white text-[11px] truncate">{item.PersonName}</h4>
