};

// ====================== MAIN APP ======================

function App() {
  const [movies, setMovies] = useState<Movie[]>([]);
  const [oscarData, setOscarData] = useState<OscarRow[]>([]);
  const [filteredMovies, setFilteredMovies] = useState<Movie[]>([]);
  const [activeTab, setActiveTab] = useState<'catalog' | 'oscars' | 'analysis'>('catalog');
  const [searchQuery, setSearchQuery] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [isDataLoading, setIsDataLoading] = useState(true);
  const [oscarYear, setOscarYear] = useState<number>(2024);
  const [isScrolled, setIsScrolled] = useState(false);

  const [filters, setFilters] = useState<FilterState>({ yearRange: [1900, 2025], ratingRange: [0, 10], genres: [], directors: [] });

  useEffect(() => {
    const loadData = async () => {
        setIsDataLoading(true);
        try {
            const csvReq = await fetch(`peliculas.csv?t=${Date.now()}`);
            if (csvReq.ok) setMovies(parseMoviesCSV(await csvReq.text()));
            const xlsxReq = await fetch(`Oscar_Data_1927_today.xlsx?t=${Date.now()}`);
            if (xlsxReq.ok) setOscarData(parseOscarExcel(await xlsxReq.arrayBuffer()));
        } catch (e) {}
        setIsDataLoading(false);
    };
    loadData();
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    let result = movies.filter(m => {
        const y = m.Year || 0;
        const r = m["Your Rating"] ?? -1;
        if (y < filters.yearRange[0] || y > filters.yearRange[1]) return false;
        if (filters.ratingRange[0] > 0 && (r < filters.ratingRange[0] || r > filters.ratingRange[1])) return false;
        if (filters.genres.length && !filters.genres.every(g => m.GenreList.includes(g))) return false;
        return true;
    });
    if (searchQuery.length > 1) {
       const fuse = new Fuse(result, { keys: ['Title', 'Directors', 'Genres'], threshold: 0.3 });
       result = fuse.search(searchQuery).map(r => r.item);
    }
    setFilteredMovies(result);
    setCurrentPage(1);
  }, [movies, filters, searchQuery]);

  const totalPages = Math.ceil(filteredMovies.length / ITEMS_PER_PAGE);
  const paginatedMovies = useMemo(() => filteredMovies.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE), [filteredMovies, currentPage]);

  const oscarDisplayData = useMemo(() => {
    const data = oscarData.filter(o => o.FilmYear === oscarYear).map(o => {
        const match = movies.find(m => normalizeTitle(m.Title) === o.NormFilm && m.Year === o.FilmYear);
        return { ...o, InMyCatalog: !!match, MyRating: match?.["Your Rating"], CatalogURL: match?.URL };
    });
    const grouped: Record<string, any[]> = {};
    data.forEach(item => { if (!grouped[item.Category]) grouped[item.Category] = []; grouped[item.Category].push(item); });
    return Object.entries(grouped).sort((a, b) => a[0].localeCompare(b[0]));
  }, [oscarData, movies, oscarYear]);

  return (
    <div className="min-h-screen text-slate-200 flex flex-col relative pb-20">
      <header className={`sticky top-0 z-50 transition-all border-b ${isScrolled ? 'bg-black/95 border-white/5' : 'bg-transparent border-transparent'} py-4`}>
          <div className="max-w-[1600px] mx-auto px-6 h-12 flex items-center justify-between">
              <div className="flex items-center gap-3">
                  <div className="w-9 h-9 bg-accent rounded-lg flex items-center justify-center text-black"><Clapperboard size={20} /></div>
                  <h1 className="text-lg font-black uppercase tracking-tighter">Mi Cine</h1>
              </div>
              <nav className="flex items-center gap-6">
                  {['catalog', 'oscars', 'analysis'].map(t => (
                      <button key={t} onClick={() => setActiveTab(t as any)} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === t ? 'text-accent border-b-2 border-accent' : 'text-slate-500'}`}>{t === 'catalog' ? 'Catálogo' : t === 'oscars' ? 'Oscars' : 'Análisis'}</button>
                  ))}
              </nav>
          </div>
      </header>

      <main className="max-w-[1600px] mx-auto px-6 w-full mt-10">
            {activeTab === 'catalog' && (
                <div className="space-y-10">
                    <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
                        <div className="relative w-full max-w-md">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                            <input type="text" placeholder="Buscar película..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-full py-2 pl-10 pr-4 text-sm focus:border-accent outline-none" />
                        </div>
                        <div className="flex items-center gap-4 text-[10px] font-black uppercase tracking-widest text-slate-500">
                             Total: <span className="text-white">{filteredMovies.length}</span>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8 gap-6">
                        {paginatedMovies.map((m, i) => <MovieCard key={i} movie={m} apiKeys={DEFAULT_API_KEYS} />)}
                    </div>

                    {totalPages > 1 && (
                        <div className="flex justify-center items-center gap-4 pt-10">
                            <button disabled={currentPage === 1} onClick={() => { setCurrentPage(currentPage - 1); window.scrollTo({top:0, behavior:'smooth'}); }} className="p-2 disabled:opacity-20 text-accent"><ChevronLeft size={24}/></button>
                            <span className="text-xs font-black">PÁGINA {currentPage} DE {totalPages}</span>
                            <button disabled={currentPage === totalPages} onClick={() => { setCurrentPage(currentPage + 1); window.scrollTo({top:0, behavior:'smooth'}); }} className="p-2 disabled:opacity-20 text-accent"><ChevronRight size={24}/></button>
                        </div>
                    )}
                </div>
            )}

            {activeTab === 'oscars' && (
                <div className="space-y-12">
                    <div className="glass-panel p-8 rounded-3xl border border-white/5 flex flex-col md:flex-row items-center justify-between gap-6">
                        <h2 className="text-3xl font-black uppercase text-yellow-500 tracking-tighter">Premios Oscar {oscarYear}</h2>
                        <div className="flex items-center gap-4 bg-black/40 p-2 rounded-xl border border-white/5">
                            <button onClick={() => setOscarYear(oscarYear - 1)} className="px-4 py-2 hover:bg-white/5 rounded-lg text-xs">Anterior</button>
                            <span className="text-2xl font-black text-white">{oscarYear}</span>
                            <button onClick={() => setOscarYear(oscarYear + 1)} className="px-4 py-2 hover:bg-white/5 rounded-lg text-xs">Siguiente</button>
                        </div>
                    </div>
                    <div className="space-y-16">
                        {oscarDisplayData.map(([cat, items]) => (
                            <div key={cat}>
                                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.4em] mb-6 border-l-2 border-yellow-500 pl-4">{cat}</h3>
                                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8 gap-4">
                                    {items.map((o, i) => <OscarCard key={i} item={o} apiKeys={DEFAULT_API_KEYS} />)}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {activeTab === 'analysis' && (
                <div className="glass-panel p-10 rounded-3xl text-center opacity-50 italic">
                    Funcionalidad de análisis en desarrollo...
                </div>
            )}
      </main>

      {isDataLoading && (
          <div className="fixed inset-0 bg-black/80 z-[100] flex items-center justify-center backdrop-blur-sm">
              <div className="text-center">
                  <Loader2 size={48} className="animate-spin text-accent mx-auto mb-4" />
                  <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Cargando Celuloide...</p>
              </div>
          </div>
      )}
    </div>
  );
}

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<React.StrictMode><App /></React.StrictMode>);

