import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';
import Fuse from 'fuse.js';
import { 
  Search, Trophy, Clapperboard, List, Settings, Loader2, Play, 
  ChevronLeft, ChevronRight, Filter, Trash2, Calendar, Star, 
  Film, Megaphone, X, Check, Activity, TrendingUp, TrendingDown, 
  Users, PieChart, Clock, ThumbsUp, ThumbsDown, ExternalLink, 
  PlayCircle, Youtube, BookOpen, CheckCircle2, FileText, History, 
  AlertTriangle 
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, 
  AreaChart, Area, ScatterChart, Scatter, Cell, ReferenceLine
} from 'recharts';

// ====================== TYPES ======================
export interface Movie {
  Title: string;
  Year: number | null;
  "Your Rating": number | null;
  "IMDb Rating": number | null;
  Genres: string;
  GenreList: string[];
  Directors: string;
  "Date Rated": string | null;
  URL: string;
  NormTitle: string;
  SearchText: string;
}

export interface OscarRow {
  FilmYear: number | null;
  AwardYear: number | null;
  CategoryRaw: string;
  Category: string;
  PersonName: string;
  Film: string;
  IsWinner: boolean;
  NormFilm: string;
  InMyCatalog?: boolean;
  MyRating?: number | null;
  MyIMDb?: number | null;
  CatalogURL?: string;
}

export interface TmdbInfo {
  id: number;
  poster_url: string | null;
  vote_average: number;
}

export interface ProviderInfo {
  platforms: string[];
  link: string | null;
}

export interface OmdbAwards {
  raw: string | null;
  oscars: number;
  emmys: number;
  baftas: number;
  golden_globes: number;
  palme_dor: boolean;
  oscars_nominated: number;
  total_wins: number;
  total_nominations: number;
  imdbRating?: string;
  error?: string;
}

export interface FilterState {
  yearRange: [number, number];
  ratingRange: [number, number];
  genres: string[];
  directors: string[];
}

export interface ApiKeys {
  tmdb: string;
  omdb: string;
  youtube: string;
}

// ====================== CONSTANTS & UTILS ======================
const APP_VERSION = "1.3.1";

const DEFAULT_API_KEYS: ApiKeys = {
  tmdb: "506c9387e637ecb32fd3b1ab6ade4259",
  omdb: "1b00f496",
  youtube: "AIzaSyBV8-kbLUzPAT9Pi1JBXP9KQBAjF0gvRHo"
};

const ITEMS_PER_PAGE = 48;

const normalizeTitle = (s: any): string => {
  if (!s) return "";
  return String(s).replace(/[^a-z0-9]+/gi, "").toLowerCase();
};

const parseMoviesCSV = (csvText: string): Movie[] => {
  const result = Papa.parse(csvText, { header: true, skipEmptyLines: true });
  const data = result.data as any[];
  return data.map(row => {
    let year = null;
    if (row.Year) {
      const match = String(row.Year).match(/(\d{4})/);
      if (match) year = parseInt(match[0], 10);
    }
    const yourRating = row["Your Rating"] ? parseFloat(row["Your Rating"]) : null;
    const imdbRating = row["IMDb Rating"] ? parseFloat(row["IMDb Rating"]) : null;
    const genres = row.Genres || "";
    const genreList = genres ? genres.split(", ").map((g:string) => g.trim()) : [];
    const directors = row.Directors || "";
    const searchFields = [row.Title, row["Original Title"], directors, genres, year, yourRating, imdbRating];
    const searchText = searchFields.filter(Boolean).join(" ").toLowerCase();
    return {
      Title: row.Title,
      Year: year,
      "Your Rating": yourRating,
      "IMDb Rating": imdbRating,
      Genres: genres,
      GenreList: genreList,
      Directors: directors,
      "Date Rated": row["Date Rated"] || null,
      URL: row.URL || "",
      NormTitle: normalizeTitle(row.Title),
      SearchText: searchText
    };
  }).filter(m => m.Title);
};

const parseOscarExcel = (buffer: ArrayBuffer) => {
  const workbook = XLSX.read(buffer, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const jsonData = XLSX.utils.sheet_to_json(sheet) as any[];
  return jsonData.map(row => {
    const filmYear = row["Year Film"] || row["Year_Film"] || row["year film"] || row["Year"] || null;
    const awardYear = row["Year Award"] || row["Ceremony"] || filmYear;
    const isWinner = !!(String(row["Winner"] || row["IsWinner"] || row["Won"]).match(/^(true|1|yes|won|winner)$/i));
    return {
      FilmYear: typeof filmYear === 'number' ? filmYear : parseInt(String(filmYear).match(/\d{4}/)?.[0] || '0'),
      AwardYear: typeof awardYear === 'number' ? awardYear : parseInt(String(awardYear).match(/\d{4}/)?.[0] || '0'),
      Category: String(row["Category"] || row["Award"] || "").trim().toUpperCase(),
      PersonName: String(row["Nominee"] || row["Name"] || ""),
      Film: String(row["Film"] || row["Movie"] || row["Title"] || ""),
      IsWinner: isWinner,
      NormFilm: normalizeTitle(row["Film"] || row["Movie"] || row["Title"] || "")
    };
  });
};

const getRatingColors = (rating: number | null) => {
  if (rating === null) return { border: "rgba(148,163,184,0.8)", glow: "rgba(15,23,42,0.0)", text: "text-slate-400" };
  if (rating >= 9) return { border: "#22c55e", glow: "rgba(34,197,94,0.55)", text: "text-green-500" };
  if (rating >= 8) return { border: "#0ea5e9", glow: "rgba(14,165,233,0.55)", text: "text-sky-500" };
  if (rating >= 7) return { border: "#a855f7", glow: "rgba(168,85,247,0.50)", text: "text-purple-500" };
  if (rating >= 6) return { border: "#eab308", glow: "rgba(234,179,8,0.45)", text: "text-yellow-500" };
  return { border: "#f97316", glow: "rgba(249,115,22,0.45)", text: "text-orange-500" };
};

// ====================== API SERVICES ======================
const TMDB_BASE = "https://api.themoviedb.org/3";
const TMDB_IMG = "https://image.tmdb.org/t/p/w342";

const fetchTmdbInfo = async (title: string, year: number | null, apiKey: string): Promise<TmdbInfo | null> => {
  if (!apiKey || !title) return null;
  try {
    const query = new URLSearchParams({ api_key: apiKey, query: title });
    if (year) query.append("year", year.toString());
    const res = await fetch(`${TMDB_BASE}/search/movie?${query}`);
    const data = await res.json();
    if (data.results?.length > 0) {
      const m = data.results[0];
      return { id: m.id, poster_url: m.poster_path ? `${TMDB_IMG}${m.poster_path}` : null, vote_average: m.vote_average };
    }
  } catch (e) {}
  return null;
};

const fetchOmdbAwards = async (title: string, year: number | null, apiKey: string): Promise<OmdbAwards | null> => {
  if (!apiKey || !title) return null;
  try {
    const query = new URLSearchParams({ apikey: apiKey, t: title, type: 'movie' });
    if (year) query.append('y', year.toString());
    const res = await fetch(`https://www.omdbapi.com/?${query}`);
    const data = await res.json();
    if (data.Response === "True") {
        const lower = (data.Awards || "").toLowerCase();
        const getNum = (regex: RegExp) => { const m = lower.match(regex); return m ? parseInt(m[1], 10) : 0; };
        return {
            raw: data.Awards === "N/A" ? null : data.Awards,
            oscars: getNum(/won\s+(\d+)\s+oscars?/),
            oscars_nominated: getNum(/nominated\s+for\s+(\d+)\s+oscars?/),
            emmys: getNum(/won\s+(\d+)\s+emmy/),
            baftas: lower.includes("bafta") ? 1 : 0,
            golden_globes: lower.includes("golden globe") ? 1 : 0,
            palme_dor: lower.includes("palme d'or"),
            total_wins: getNum(/(\d+)\s+wins?/),
            total_nominations: getNum(/(\d+)\s+nominations?/),
            imdbRating: data.imdbRating !== "N/A" ? data.imdbRating : undefined
        };
    }
  } catch (e) {}
  return null;
};

const getYoutubeTrailer = async (title: string, year: number | null, apiKey: string): Promise<string | null> => {
    if (!apiKey || !title) return null;
    try {
        const q = `${title} trailer ${year || ''}`;
        const res = await fetch(`https://www.googleapis.com/youtube/v3/search?part=snippet&q=${encodeURIComponent(q)}&type=video&maxResults=1&key=${apiKey}`);
        const data = await res.json();
        return data.items?.[0]?.id?.videoId || null;
    } catch (e) {}
    return null;
};

// ====================== COMPONENTS ======================

const MovieCard: React.FC<{ movie: Movie; apiKeys: ApiKeys }> = ({ movie, apiKeys }) => {
  const [tmdb, setTmdb] = useState<TmdbInfo | null>(null);
  const [awards, setAwards] = useState<OmdbAwards | null>(null);
  const [trailerId, setTrailerId] = useState<string | null>(null);

  useEffect(() => {
    fetchTmdbInfo(movie.Title, movie.Year, apiKeys.tmdb).then(setTmdb);
    fetchOmdbAwards(movie.Title, movie.Year, apiKeys.omdb).then(setAwards);
    getYoutubeTrailer(movie.Title, movie.Year, apiKeys.youtube).then(setTrailerId);
  }, [movie, apiKeys]);

  const rating = movie["Your Rating"] ?? movie["IMDb Rating"];
  const colors = getRatingColors(rating);
  const trailerUrl = trailerId ? `https://www.youtube.com/watch?v=${trailerId}` : `https://www.youtube.com/results?search_query=${encodeURIComponent(movie.Title + " trailer")}`;

  return (
    <div className="group relative bg-[#050505] rounded-lg overflow-hidden transition-all duration-500 hover:scale-105 hover:shadow-2xl border border-white/5 hover:border-white/20">
      <div className="aspect-[2/3] w-full bg-slate-900 relative overflow-hidden">
        {tmdb?.poster_url ? <img src={tmdb.poster_url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt="" /> : <div className="w-full h-full flex items-center justify-center text-slate-800"><Film size={32} /></div>}
        <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-60 group-hover:opacity-90" />
        <div className="absolute top-2 left-2 flex gap-1">
            {awards?.oscars ? <span className="bg-yellow-500 text-black text-[9px] px-1.5 py-0.5 rounded font-black">🏆 {awards.oscars}</span> : null}
        </div>
      </div>
      <div className="absolute bottom-0 left-0 right-0 p-3 transform translate-y-2 group-hover:translate-y-0 transition-transform duration-300">
        <h3 className="font-bold text-white text-[13px] leading-tight mb-0.5 line-clamp-2">{movie.Title}</h3>
        <div className="text-[10px] text-slate-400 mb-2">{movie.Year}</div>
        <div className="flex items-center gap-2 text-[11px] mb-2">
            {movie["Your Rating"] && <div className={`flex items-center gap-0.5 font-black ${colors.text}`}><Star size={10} fill="currentColor" /> {movie["Your Rating"]}</div>}
            {movie["IMDb Rating"] && <div className="text-slate-500"><span className="text-[9px] text-yellow-500 border border-yellow-500/30 px-0.5 rounded mr-1">IMDb</span>{movie["IMDb Rating"]}</div>}
        </div>
        <div className="h-0 group-hover:h-auto overflow-hidden opacity-0 group-hover:opacity-100 transition-all border-t border-white/10 pt-2 flex gap-1">
             <a href={movie.URL} target="_blank" rel="noreferrer" className="flex-1 py-1 bg-white/10 hover:bg-white/20 rounded flex justify-center"><ExternalLink size={12} /></a>
             <a href={trailerUrl} target="_blank" rel="noreferrer" className="flex-1 py-1 bg-red-500/10 hover:bg-red-500/20 rounded flex justify-center text-red-500"><Youtube size={12} /></a>
        </div>
      </div>
    </div>
  );
};

const OscarCard: React.FC<{ item: OscarRow; apiKeys: ApiKeys }> = ({ item, apiKeys }) => {
  const [tmdb, setTmdb] = useState<TmdbInfo | null>(null);
  useEffect(() => { fetchTmdbInfo(item.Film, item.FilmYear, apiKeys.tmdb).then(setTmdb); }, [item, apiKeys]);
  const imdbUrl = item.CatalogURL || `https://www.imdb.com/find?q=${encodeURIComponent(item.Film + " " + item.FilmYear)}`;
  return (
    <div className={`group relative bg-[#050505] rounded-xl overflow-hidden border ${item.IsWinner ? 'border-yellow-500/30' : 'border-white/5'} hover:scale-105 transition-all`}>
      <div className="aspect-[2/3] w-full bg-slate-900 relative">
        {tmdb?.poster_url ? <img src={tmdb.poster_url} className="w-full h-full object-cover" alt="" /> : <div className="w-full h-full flex items-center justify-center text-slate-800"><Film size={24} /></div>}
        {item.IsWinner && <div className="absolute top-2 left-2 bg-yellow-500 text-black text-[8px] font-black px-1.5 py-0.5 rounded">GANADOR</div>}
        {item.InMyCatalog && <div className="absolute top-2 right-2 bg-green-500 text-white text-[8px] font-black px-1.5 py-0.5 rounded">VISTO</div>}
      </div>
      <div className="p-3">
        <h4 className="font-black text-white text-[11px] truncate">{item.PersonName}</h4>
        <div className="text-[9px] text-slate-500 truncate mb-2">{item.Film} ({item.FilmYear})</div>
        <a href={imdbUrl} target="_blank" rel="noreferrer" className="block text-center py-1 bg-white/5 hover:bg-white/10 rounded text-[9px] uppercase font-bold text-slate-400">Ver Ficha</a>
      </div>
    </div>
  );
};

// ====================== MAIN APP ======================

function App() {
  const [movies, setMovies] = useState<Movie[]>([]);
  const [oscarData, setOscarData] = useState<OscarRow[]>([]);
  const [filteredMovies, setFilteredMovies] = useState<Movie[]>([]);
  const [activeTab, setActiveTab] = useState<'catalog' | 'oscars' | 'analysis'>('catalog');
  const [searchQuery, setSearchQuery] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [isDataLoading, setIsDataLoading] = useState(true);
  const [oscarYear, setOscarYear] = useState<number>(2024);
  const [isScrolled, setIsScrolled] = useState(false);

  const [filters, setFilters] = useState<FilterState>({ yearRange: [1900, 2025], ratingRange: [0, 10], genres: [], directors: [] });

  useEffect(() => {
    const loadData = async () => {
        setIsDataLoading(true);
        try {
            const csvReq = await fetch(`peliculas.csv?t=${Date.now()}`);
            if (csvReq.ok) setMovies(parseMoviesCSV(await csvReq.text()));
            const xlsxReq = await fetch(`Oscar_Data_1927_today.xlsx?t=${Date.now()}`);
            if (xlsxReq.ok) setOscarData(parseOscarExcel(await xlsxReq.arrayBuffer()));
        } catch (e) {}
        setIsDataLoading(false);
    };
    loadData();
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    let result = movies.filter(m => {
        const y = m.Year || 0;
        const r = m["Your Rating"] ?? -1;
        if (y < filters.yearRange[0] || y > filters.yearRange[1]) return false;
        if (filters.ratingRange[0] > 0 && (r < filters.ratingRange[0] || r > filters.ratingRange[1])) return false;
        if (filters.genres.length && !filters.genres.every(g => m.GenreList.includes(g))) return false;
        return true;
    });
    if (searchQuery.length > 1) {
       const fuse = new Fuse(result, { keys: ['Title', 'Directors', 'Genres'], threshold: 0.3 });
       result = fuse.search(searchQuery).map(r => r.item);
    }
    setFilteredMovies(result);
    setCurrentPage(1);
  }, [movies, filters, searchQuery]);

  const totalPages = Math.ceil(filteredMovies.length / ITEMS_PER_PAGE);
  const paginatedMovies = useMemo(() => filteredMovies.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE), [filteredMovies, currentPage]);

  const oscarDisplayData = useMemo(() => {
    const data = oscarData.filter(o => o.FilmYear === oscarYear).map(o => {
        const match = movies.find(m => normalizeTitle(m.Title) === o.NormFilm && m.Year === o.FilmYear);
        return { ...o, InMyCatalog: !!match, MyRating: match?.["Your Rating"], CatalogURL: match?.URL };
    });
    const grouped: Record<string, any[]> = {};
    data.forEach(item => { if (!grouped[item.Category]) grouped[item.Category] = []; grouped[item.Category].push(item); });
    return Object.entries(grouped).sort((a, b) => a[0].localeCompare(b[0]));
  }, [oscarData, movies, oscarYear]);

  return (
    <div className="min-h-screen text-slate-200 flex flex-col relative pb-20">
      <header className={`sticky top-0 z-50 transition-all border-b ${isScrolled ? 'bg-black/95 border-white/5' : 'bg-transparent border-transparent'} py-4`}>
          <div className="max-w-[1600px] mx-auto px-6 h-12 flex items-center justify-between">
              <div className="flex items-center gap-3">
                  <div className="w-9 h-9 bg-accent rounded-lg flex items-center justify-center text-black"><Clapperboard size={20} /></div>
                  <h1 className="text-lg font-black uppercase tracking-tighter">Mi Cine</h1>
              </div>
              <nav className="flex items-center gap-6">
                  {['catalog', 'oscars', 'analysis'].map(t => (
                      <button key={t} onClick={() => setActiveTab(t as any)} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === t ? 'text-accent border-b-2 border-accent' : 'text-slate-500'}`}>{t === 'catalog' ? 'Catálogo' : t === 'oscars' ? 'Oscars' : 'Análisis'}</button>
                  ))}
              </nav>
          </div>
      </header>

      <main className="max-w-[1600px] mx-auto px-6 w-full mt-10">
            {activeTab === 'catalog' && (
                <div className="space-y-10">
                    <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
                        <div className="relative w-full max-w-md">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                            <input type="text" placeholder="Buscar película..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-full py-2 pl-10 pr-4 text-sm focus:border-accent outline-none" />
                        </div>
                        <div className="flex items-center gap-4 text-[10px] font-black uppercase tracking-widest text-slate-500">
                             Total: <span className="text-white">{filteredMovies.length}</span>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8 gap-6">
                        {paginatedMovies.map((m, i) => <MovieCard key={i} movie={m} apiKeys={DEFAULT_API_KEYS} />)}
                    </div>

                    {totalPages > 1 && (
                        <div className="flex justify-center items-center gap-4 pt-10">
                            <button disabled={currentPage === 1} onClick={() => { setCurrentPage(currentPage - 1); window.scrollTo({top:0, behavior:'smooth'}); }} className="p-2 disabled:opacity-20 text-accent"><ChevronLeft size={24}/></button>
                            <span className="text-xs font-black">PÁGINA {currentPage} DE {totalPages}</span>
                            <button disabled={currentPage === totalPages} onClick={() => { setCurrentPage(currentPage + 1); window.scrollTo({top:0, behavior:'smooth'}); }} className="p-2 disabled:opacity-20 text-accent"><ChevronRight size={24}/></button>
                        </div>
                    )}
                </div>
            )}

            {activeTab === 'oscars' && (
                <div className="space-y-12">
                    <div className="glass-panel p-8 rounded-3xl border border-white/5 flex flex-col md:flex-row items-center justify-between gap-6">
                        <h2 className="text-3xl font-black uppercase text-yellow-500 tracking-tighter">Premios Oscar {oscarYear}</h2>
                        <div className="flex items-center gap-4 bg-black/40 p-2 rounded-xl border border-white/5">
                            <button onClick={() => setOscarYear(oscarYear - 1)} className="px-4 py-2 hover:bg-white/5 rounded-lg text-xs">Anterior</button>
                            <span className="text-2xl font-black text-white">{oscarYear}</span>
                            <button onClick={() => setOscarYear(oscarYear + 1)} className="px-4 py-2 hover:bg-white/5 rounded-lg text-xs">Siguiente</button>
                        </div>
                    </div>
                    <div className="space-y-16">
                        {oscarDisplayData.map(([cat, items]) => (
                            <div key={cat}>
                                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.4em] mb-6 border-l-2 border-yellow-500 pl-4">{cat}</h3>
                                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8 gap-4">
                                    {items.map((o, i) => <OscarCard key={i} item={o} apiKeys={DEFAULT_API_KEYS} />)}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {activeTab === 'analysis' && (
                <div className="glass-panel p-10 rounded-3xl text-center opacity-50 italic">
                    Funcionalidad de análisis en desarrollo...
                </div>
            )}
      </main>

      {isDataLoading && (
          <div className="fixed inset-0 bg-black/80 z-[100] flex items-center justify-center backdrop-blur-sm">
              <div className="text-center">
                  <Loader2 size={48} className="animate-spin text-accent mx-auto mb-4" />
                  <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Cargando Celuloide...</p>
              </div>
          </div>
      )}
    </div>
  );
}

// Added export default for App component
export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Movie, FilterState, ApiKeys, OscarRow } from './types';
import { parseMoviesCSV, parseOscarExcel, normalizeTitle } from './utils';
import { AFI_LIST } from './constants';
import SettingsModal from './components/SettingsModal';
import FilterBar from './components/FilterBar';
import MovieCard from './components/MovieCard';
import OscarCard from './components/OscarCard';
import AFICard from './components/AFICard';
import OscarMovieSummary from './components/OscarMovieSummary';
import AnalysisView from './components/AnalysisView';
import { Search, Trophy, Clapperboard, List, Dice5, Star, Settings, BarChart3, Loader2, Play, ChevronLeft, ChevronRight } from 'lucide-react';
import Fuse from 'fuse.js';

const DEFAULT_API_KEYS: ApiKeys = {
  tmdb: "506c9387e637ecb32fd3b1ab6ade4259",
  omdb: "1b00f496",
  youtube: "AIzaSyBV8-kbLUzPAT9Pi1JBXP9KQBAjF0gvRHo"
};

const ITEMS_PER_PAGE = 48;

function App() {
  const [movies, setMovies] = useState<Movie[]>([]);
  const [oscarData, setOscarData] = useState<OscarRow[]>([]);
  const [filteredMovies, setFilteredMovies] = useState<Movie[]>([]);
  const [activeTab, setActiveTab] = useState<'catalog' | 'analysis' | 'afi' | 'oscars' | 'random'>('catalog');
  const [searchQuery, setSearchQuery] = useState("");
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [isDataLoading, setIsDataLoading] = useState(true);
  const [selectedOscarMovieTitle, setSelectedOscarMovieTitle] = useState<string | null>(null);

  const [filters, setFilters] = useState<FilterState>({
    yearRange: [1900, new Date().getFullYear() + 1],
    ratingRange: [0, 10],
    genres: [],
    directors: []
  });

  const [apiKeys] = useState<ApiKeys>(DEFAULT_API_KEYS);

  useEffect(() => {
    const loadData = async () => {
        setIsDataLoading(true);
        try {
            const csvReq = await fetch(`peliculas.csv?t=${Date.now()}`, { cache: 'no-store' });
            if (csvReq.ok) {
                const text = await csvReq.text();
                if (text && text.length > 50) setMovies(parseMoviesCSV(text));
            }
        } catch (e) { console.warn("CSV no disponible"); }

        try {
            const xlsxReq = await fetch(`Oscar_Data_1927_today.xlsx?t=${Date.now()}`, { cache: 'no-store' });
            if (xlsxReq.ok) {
                const buf = await xlsxReq.arrayBuffer();
                if (buf && buf.byteLength > 100) setOscarData(parseOscarExcel(buf));
            }
        } catch (e) { console.warn("Excel no disponible"); }

        setIsDataLoading(false);
    };

    loadData();
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const availableGenres = useMemo(() => Array.from(new Set(movies.flatMap(m => m.GenreList))).sort(), [movies]);
  const availableDirectors = useMemo(() => Array.from(new Set(movies.flatMap(m => m.Directors.split(',').map(d => d.trim()).filter(Boolean)))).sort(), [movies]);

  useEffect(() => {
    let result = movies.filter(m => {
        const y = m.Year || 0;
        const r = m["Your Rating"] ?? -1;
        if (y !== 0 && (y < filters.yearRange[0] || y > filters.yearRange[1])) return false;
        if (filters.ratingRange[0] > 0 && (r < filters.ratingRange[0] || r > filters.ratingRange[1])) return false;
        if (filters.genres.length && !filters.genres.every(g => m.GenreList.includes(g))) return false;
        if (filters.directors.length && !filters.directors.some(d => m.Directors.includes(d))) return false;
        return true;
    });

    if (searchQuery.length > 1) {
       const fuse = new Fuse(result, { keys: ['Title', 'Directors', 'Genres', 'Year'], threshold: 0.3 });
       result = fuse.search(searchQuery).map(r => r.item);
    }
    setFilteredMovies(result);
    setCurrentPage(1);
  }, [movies, filters, searchQuery]);

  const totalPages = Math.ceil(filteredMovies.length / ITEMS_PER_PAGE);

  const paginatedMovies = useMemo(() => {
      const start = (currentPage - 1) * ITEMS_PER_PAGE;
      return filteredMovies.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredMovies, currentPage]);

  const [oscarYear, setOscarYear] = useState<number>(2024);
  const [showOnlyWinners, setShowOnlyWinners] = useState(false);

  const availableOscarYears = useMemo(() => {
    const years = new Set(oscarData.map(o => o.FilmYear).filter((y): y is number => y !== null));
    return Array.from(years).sort((a: number, b: number) => b - a);
  }, [oscarData]);

  const oscarFiltered = useMemo(() => {
    return oscarData.map(o => {
        const match = movies.find(m => m.NormTitle === o.NormFilm && m.Year === o.FilmYear);
        return { ...o, InMyCatalog: !!match, MyRating: match?.["Your Rating"], MyIMDb: match?.["IMDb Rating"], CatalogURL: match?.URL };
    });
  }, [oscarData, movies]);

  const oscarDisplayData = useMemo(() => {
    let data = oscarFiltered.filter(o => o.FilmYear === oscarYear);
    if (showOnlyWinners) data = data.filter(o => o.IsWinner);
    const grouped: Record<string, OscarRow[]> = {};
    data.forEach(item => {
        if (!grouped[item.Category]) grouped[item.Category] = [];
        grouped[item.Category].push(item);
    });
    return Object.entries(grouped).sort((a, b) => a[0].localeCompare(b[0]));
  }, [oscarFiltered, oscarYear, showOnlyWinners]);

  const oscarLeaderboard = useMemo(() => {
      const yearData = oscarFiltered.filter(o => o.FilmYear === oscarYear);
      const statsMap: Record<string, {title: string, wins: number, noms: number, isWinner: boolean}> = {};
      yearData.forEach(row => {
          let entry = statsMap[row.Film];
          if (!entry) {
              entry = { title: row.Film, wins: 0, noms: 0, isWinner: false };
              statsMap[row.Film] = entry;
          }
          entry.noms += 1;
          if (row.IsWinner) {
              entry.wins += 1;
              entry.isWinner = true;
          }
      });
      return Object.values(statsMap).sort((a: any, b: any) => b.wins !== a.wins ? b.wins - a.wins : b.noms - a.noms);
  }, [oscarFiltered, oscarYear]);

  const handlePageChange = (newPage: number) => {
    setCurrentPage(newPage);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const GRID_CLASS = "grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 2xl:grid-cols-8 gap-x-6 gap-y-12";

  return (
    <div className="min-h-screen text-slate-200 font-sans flex flex-col relative">
      <div className="bg-cinematic"></div>
      <div className="bg-noise"></div>

      <SettingsModal 
        isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)}
        onFileUpload={(file, type) => {
            const reader = new FileReader();
            reader.onload = (e) => {
                if (type === 'movies') setMovies(parseMoviesCSV(e.target?.result as string));
                else setOscarData(parseOscarExcel(e.target?.result as ArrayBuffer));
            };
            if (type === 'movies') reader.readAsText(file); else reader.readAsArrayBuffer(file);
        }}
        onClearData={() => { setMovies([]); setOscarData([]); setFilteredMovies([]); }}
      />

      <header className={`sticky top-0 z-50 transition-all duration-500 border-b ${isScrolled ? 'bg-black/95 backdrop-blur-xl border-white/5 py-2' : 'bg-transparent border-transparent py-4'}`}>
          <div className="max-w-[1920px] mx-auto px-4 lg:px-8 h-16 flex items-center justify-between gap-6">
              <div className="flex items-center gap-3 shrink-0 group cursor-pointer" onClick={() => setActiveTab('catalog')}>
                  <div className="w-10 h-10 bg-gradient-to-br from-accent to-yellow-600 rounded-xl flex items-center justify-center text-primary shadow-[0_0_20px_rgba(234,179,8,0.4)]">
                      <Clapperboard size={24} strokeWidth={2.5} />
                  </div>
                  <div>
                      <h1 className="text-xl font-black uppercase tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent leading-none">Mi Cine</h1>
                      <div className="text-[10px] font-black text-accent tracking-[0.3em] uppercase opacity-90 mt-1">Catálogo Personal</div>
                  </div>
              </div>

              <div className="hidden md:flex flex-1 max-w-xl mx-auto px-4">
                  <div className="relative group w-full">
                       <input 
                           type="text" 
                           placeholder="Buscar película..." 
                           value={searchQuery}
                           onChange={(e) => setSearchQuery(e.target.value)}
                           className="w-full bg-white/5 border border-white/10 rounded-full py-2.5 pl-12 pr-4 text-sm focus:border-accent/50 outline-none backdrop-blur-md"
                       />
                       <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                  </div>
              </div>

              <nav className="flex items-center gap-4">
                  <div className="hidden lg:flex items-center gap-1">
                     {[
                        { id: 'catalog', label: 'Catálogo' },
                        { id: 'analysis', label: 'Análisis' },
                        { id: 'oscars', label: 'Premios Oscar' },
                        { id: 'afi', label: 'Lista AFI' },
                        { id: 'random', label: 'Qué veo hoy' },
                      ].map(tab => (
                        <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`px-4 py-2 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab.id ? 'text-white border-b-2 border-accent' : 'text-slate-500 hover:text-slate-300'}`}>
                            {tab.label}
                        </button>
                      ))}
                  </div>
                  <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-slate-400 hover:text-white transition-colors"><Settings size={20} /></button>
              </nav>
          </div>
      </header>

      <main className="max-w-[1920px] mx-auto p-4 lg:p-8 w-full flex-1 relative z-10">
            {activeTab === 'catalog' && (
                <div className="animate-in fade-in duration-700">
                    <FilterBar filters={filters} setFilters={setFilters} availableGenres={availableGenres} availableDirectors={availableDirectors} movies={movies} />
                    {isDataLoading && movies.length === 0 ? (
                        <div className="flex flex-col items-center justify-center py-40"><Loader2 size={48} className="animate-spin text-accent mb-4" /><p className="text-[10px] font-black uppercase tracking-widest text-slate-500">Iniciando Función...</p></div>
                    ) : filteredMovies.length === 0 ? (
                        <div className="text-center py-40 opacity-20"><Clapperboard size={80} className="mx-auto mb-4" /><p className="font-black uppercase tracking-widest">No se encontraron películas</p></div>
                    ) : (
                        <>
                            <div className={GRID_CLASS}>
                                {paginatedMovies.map((m, i) => <MovieCard key={`${m.Title}-${i}`} movie={m} apiKeys={apiKeys} />)}
                            </div>

                            {/* Paginación Numérica */}
                            {totalPages > 1 && (
                                <div className="flex flex-col items-center mt-16 mb-8 gap-4">
                                    <div className="glass-panel px-4 py-2 rounded-full flex items-center gap-2 shadow-lg">
                                        {/* Prev */}
                                        <button 
                                            onClick={() => handlePageChange(currentPage - 1)} 
                                            disabled={currentPage === 1}
                                            className="p-2 rounded-full hover:bg-white/10 disabled:opacity-30 disabled:hover:bg-transparent transition-colors text-slate-300"
                                        >
                                            <ChevronLeft size={20} />
                                        </button>

                                        {/* Page Numbers */}
                                        <div className="hidden sm:flex items-center gap-1">
                                            {(() => {
                                                const pages = [];
                                                if (totalPages <= 7) {
                                                    for (let i = 1; i <= totalPages; i++) pages.push(i);
                                                } else {
                                                    pages.push(1);
                                                    if (currentPage > 3) pages.push('...');
                                                    let start = Math.max(2, currentPage - 1);
                                                    let end = Math.min(totalPages - 1, currentPage + 1);
                                                    if (currentPage <= 3) { end = 4; }
                                                    if (currentPage >= totalPages - 2) { start = totalPages - 3; }
                                                    for (let i = start; i <= end; i++) pages.push(i);
                                                    if (currentPage < totalPages - 2) pages.push('...');
                                                    pages.push(totalPages);
                                                }
                                                return pages.map((p, idx) => (
                                                    <button
                                                        key={idx}
                                                        onClick={() => typeof p === 'number' && handlePageChange(p)}
                                                        disabled={p === '...'}
                                                        className={`
                                                            w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all
                                                            ${p === currentPage 
                                                                ? 'bg-accent text-black shadow-[0_0_15px_rgba(234,179,8,0.5)] scale-110' 
                                                                : p === '...' 
                                                                    ? 'text-slate-500 cursor-default' 
                                                                    : 'text-slate-400 hover:bg-white/10 hover:text-white'}
                                                        `}
                                                    >
                                                        {p}
                                                    </button>
                                                ));
                                            })()}
                                        </div>

                                        {/* Mobile simple counter (visible only on small screens) */}
                                        <span className="sm:hidden text-xs font-bold uppercase tracking-widest text-slate-400">
                                            <span className="text-white">{currentPage}</span> / <span className="text-white">{totalPages}</span>
                                        </span>

                                        {/* Next */}
                                        <button 
                                            onClick={() => handlePageChange(currentPage + 1)} 
                                            disabled={currentPage === totalPages}
                                            className="p-2 rounded-full hover:bg-white/10 disabled:opacity-30 disabled:hover:bg-transparent transition-colors text-slate-300"
                                        >
                                            <ChevronRight size={20} />
                                        </button>
                                    </div>
                                    <div className="text-[10px] text-slate-600 uppercase tracking-wider font-bold">
                                        {filteredMovies.length} Títulos Encontrados
                                    </div>
                                </div>
                            )}
                        </>
                    )}
                </div>
            )}

            {activeTab === 'oscars' && (
                <div className="space-y-12 animate-in fade-in duration-700">
                    <div className="glass-panel p-8 rounded-3xl border border-white/5 relative overflow-hidden shadow-2xl">
                        <div className="flex flex-col md:flex-row items-center justify-between gap-8 mb-12">
                             <div className="flex items-center gap-6">
                                <div className="w-16 h-16 bg-yellow-500/10 rounded-full flex items-center justify-center border border-yellow-500/20 shadow-[0_0_30px_rgba(234,179,8,0.2)]">
                                    <Trophy size={32} className="text-yellow-500" />
                                </div>
                                <div><h2 className="text-4xl font-black uppercase text-yellow-500 tracking-tighter leading-none">Premios Oscar</h2><p className="text-[10px] text-yellow-500/60 font-black uppercase tracking-[0.2em] mt-2">Archivo Histórico de la Academia</p></div>
                            </div>
                            <div className="flex items-center gap-4 bg-black/40 p-2 rounded-2xl border border-white/5 shadow-xl">
                                <button onClick={() => setOscarYear(oscarYear - 1)} className="p-3 hover:bg-white/5 rounded-xl transition-colors">Ant</button>
                                <div className="px-12 py-3 bg-yellow-500 text-black rounded-xl font-black text-3xl shadow-lg">{oscarYear}</div>
                                <button onClick={() => setOscarYear(oscarYear + 1)} className="p-3 hover:bg-white/5 rounded-xl transition-colors">Sig</button>
                            </div>
                        </div>
                        <div className="flex overflow-x-auto gap-2 pb-4 no-scrollbar scroll-smooth">
                            {availableOscarYears.map(y => (
                                <button key={y} onClick={() => setOscarYear(y)} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shrink-0 ${oscarYear === y ? 'bg-yellow-500 text-black shadow-xl' : 'bg-white/5 text-slate-500 hover:text-white hover:bg-white/10'}`}>{y}</button>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-20">
                        {oscarDisplayData.map(([cat, items]) => (
                            <div key={cat} className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                                <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.4em] mb-8 border-l-4 border-yellow-500 pl-4 bg-gradient-to-r from-yellow-500/5 to-transparent py-2">{cat}</h3>
                                <div className={GRID_CLASS}>
                                    {items.map((o, i) => (
                                        <OscarCard key={`${cat}-${i}`} item={o} apiKeys={apiKeys} />
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>

                    {oscarLeaderboard.length > 0 && (
                        <div className="mt-32 pt-16 border-t border-white/5">
                             <h3 className="text-2xl font-black text-white uppercase tracking-tight mb-12 flex items-center gap-4"><List className="text-yellow-500" /> Ranking y Desglose por Película</h3>
                             <div className="flex flex-col lg:flex-row gap-8 h-[650px]">
                                 <div className="lg:w-1/3 glass-panel rounded-2xl border border-white/5 overflow-y-auto custom-scrollbar p-3 space-y-2 bg-black/20">
                                     {oscarLeaderboard.map((m) => (
                                         <button key={m.title} onClick={() => setSelectedOscarMovieTitle(m.title)} className={`w-full flex items-center justify-between p-4 rounded-xl transition-all border ${selectedOscarMovieTitle === m.title ? 'bg-yellow-500/10 border-yellow-500/40 shadow-xl' : 'bg-transparent border-transparent hover:bg-white/5'}`}>
                                             <div className="flex items-center gap-4 truncate pr-2">
                                                 {m.isWinner && <Trophy size={14} className="text-yellow-500 shrink-0" />}
                                                 <span className={`text-[11px] font-black uppercase tracking-wide truncate ${selectedOscarMovieTitle === m.title ? 'text-white' : 'text-slate-400'}`}>{m.title}</span>
                                             </div>
                                             <div className="flex gap-4 shrink-0"><span className="text-[10px] font-black text-yellow-500">{m.wins}W</span><span className="text-[10px] font-black text-slate-600">{m.noms}N</span></div>
                                         </button>
                                     ))}
                                 </div>
                                 <div className="lg:w-2/3 h-full">
                                     {selectedOscarMovieTitle ? (
                                         <OscarMovieSummary title={selectedOscarMovieTitle} year={oscarYear} oscarData={oscarData} apiKeys={apiKeys} movies={movies} />
                                     ) : (
