                        <p className="text-accent font-black uppercase tracking-[0.6em] text-[10px]">100 Years... 100 Movies (10th Anniversary)</p>
                    </div>
                    <div className="grid grid-cols-1 gap-8">
                        {AFI_LIST.map(a => (
