                                key={a.Rank} 
                                rank={a.Rank} 
                                title={a.Title} 
                                year={a.Year} 
                                movie={movies.find(m => m.NormTitle === normalizeTitle(a.Title))} 
                                apiKeys={apiKeys} 
                            />
                        ))}
