        if (!grouped[item.Category]) grouped[item.Category] = [];
        grouped[item.Category].push(item);
    });

    return Object.entries(grouped).sort((a, b) => a[0].localeCompare(b[0]));
  }, [oscarFiltered, oscarYear, showOnlyWinners]);

